import * as React from "react";
import { Button } from "@/components/ui/button";

export function Modal({
  open,
  onClose,
  title,
  children,
  footer,
  maxWidthClassName = "max-w-[640px]",
}: {
  open: boolean;
  onClose: () => void;
  title?: React.ReactNode;
  children: React.ReactNode;
  footer?: React.ReactNode;
  maxWidthClassName?: string;
}) {
  if (!open) return null;
  return (
    <div className="fixed inset-0 z-[2100] bg-black/10 backdrop-blur-[2px] flex items-center justify-center p-4 transition-all duration-300 animate-in fade-in" onClick={onClose}>
      <div
        className={`w-full ${maxWidthClassName} rounded-xl border border-border bg-background shadow-2xl max-h-[85vh] overflow-y-auto animate-in zoom-in-95 duration-300`}
        onClick={(e) => e.stopPropagation()}
      >
        {title ? (
          <div className="px-5 py-4 border-b border-border flex items-center justify-between gap-3">
            <div className="text-lg font-semibold">{title}</div>
            <Button variant="outline" size="sm" onClick={onClose}>
              关闭
            </Button>
          </div>
        ) : null}
        <div className="p-5">{children}</div>
        {footer ? <div className="px-5 pb-5 pt-0">{footer}</div> : null}
      </div>
    </div>
  );
}

